async (params, browser) => {
  // Open hotel page
  await browser.open(`${params.hotel_url}`)

  // Wait for hotel page to load
  await browser.waitForSelector('[data-test-target=\'hr-about-section\'], h1#HEADING, .hotelDescription, [class*=\'HotelHeader\']', 15000)

  // Let page fully render
  await browser.wait(3000)

  // Scroll to load amenities section
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Extract hotel details
  const result = await browser.evaluate(`const nameEl = document.querySelector('h1#HEADING, h1[data-test-target="top-info-header"], h1[class*="hotel"], [data-test-target="hotel-header"]'); const name = nameEl ? nameEl.textContent.trim() : ''; const ratingEl = document.querySelector('svg[aria-label*="bubble"], .ui_bubble_rating, [class*="ratingValue"], span[class*="rating"]'); const rating = ratingEl ? (ratingEl.getAttribute('aria-label') || ratingEl.textContent.trim() || '') : ''; const reviewCountEl = document.querySelector('a[href*="#REVIEWS"] span, [class*="reviewCount"], [data-test-target="review-count"]'); const reviewCount = reviewCountEl ? reviewCountEl.textContent.trim() : ''; const priceEl = document.querySelector('[data-test-target="price-summary"], [class*="priceRange"], [class*="price"], .priceRange'); const price = priceEl ? priceEl.textContent.trim() : ''; const rankEl = document.querySelector('[class*="ranking"], [data-test-target="hotel-ranking"], .popRanking'); const ranking = rankEl ? rankEl.textContent.trim() : ''; const addressEl = document.querySelector('[class*="address"], [data-test-target="address-text"], span[class*="street"], .address'); const address = addressEl ? addressEl.textContent.trim() : ''; const descEl = document.querySelector('[class*="description"], [data-test-target="about-description"], .hotelDescription, [class*="aboutText"]'); const description = descEl ? descEl.textContent.trim().substring(0, 500) : ''; const amenities = []; const amenityEls = document.querySelectorAll('[data-test-target="amenity-name"], [class*="amenity"] span, .amenityList span, [class*="AmenityItem"]'); for (const el of amenityEls) { const text = el.textContent.trim(); if (text && text.length < 50 && !amenities.includes(text)) amenities.push(text); } const classEl = document.querySelector('[class*="hotelClass"], [class*="starRating"], svg[aria-label*="star"]'); const hotelClass = classEl ? (classEl.getAttribute('aria-label') || classEl.textContent.trim() || '') : ''; const imgEl = document.querySelector('img[class*="photo"], img[data-test-target="hero-photo"], [class*="heroPhoto"] img, .hotels-hero-photo img'); const image = imgEl ? imgEl.src : ''; return { name: name, rating: rating, review_count: reviewCount, price_range: price, ranking: ranking, hotel_class: hotelClass, address: address, description: description, amenities: amenities.slice(0, 20), image: image, url: window.location.href }`)

  return result
}
